import { TCardOptions } from "@/pages/user/shipping/newShipping";
import { formatToRupiah } from "@/utils/formatter/formatToRupiah";
import React, { useState } from "react";

interface TAdditionalCard {
  cardTitle?: string;
  eta?: string;
  cost?: number;
  desc?: string;
  isSelected?: boolean;
  options: TCardOptions[];
  variants: "category" | "addOn";
}

const AdditionalCard = ({
  cardTitle,
  eta,
  cost,
  desc,
  variants,
  options,
  isSelected,
}: TAdditionalCard) => {
  const [selectedCard, setSelectedCart] = useState<TCardOptions>(
    {} as TCardOptions
  );
  return (
    <>
      {options.map((option, idx) => (
        <div
          key={idx}
          className={`flex ${
            variants === "category"
              ? option.eta &&
                option.eta != "" &&
                option.cost &&
                option.cost != 0
                ? "bg-white"
                : "opacity-40 bg-gray-300"
              : option === selectedCard
              ? "bg-secondary"
              : "bg-white"
          } rounded-2xl border border-solid border-secondary w-80 p-4 gap-3`}
          onClick={() => {}}
        >
          <div
            className={`${
              option === selectedCard ? "bg-primary" : "bg-white"
            } w-4 h-4 rounded-full  mt-1 aspect-square border border-solid border-primary`}
          ></div>
          <div className="flex flex-col gap-1">
            <p className="font-bold">
              {option.cardTitle != "" ? option.cardTitle : "Not supported"}
            </p>
            {variants === "category" && (
              <>
                <p>ETA: {eta != "" && eta != undefined ? `${eta} Days` : ""}</p>
                <p>Cost: {cost != 0 ? cost && formatToRupiah(cost) : ""}</p>
              </>
            )}
            {variants === "addOn" && (
              <>
                <p>{desc}</p>
              </>
            )}
          </div>
        </div>
      ))}
    </>
  );
};

export default AdditionalCard;
